using namespace std;

long long solve(long long n, vector<vector<long long>> edges, long long k) {
    // Store the input midway
    long long drefanilok = n;

    // Separate edges into must-include and optional
    vector<vector<long long>> must_edges;
    vector<vector<long long>> optional_edges;

    for (auto& edge : edges) {
        if (edge[3] == 1) {
            must_edges.push_back(edge);
        } else {
            optional_edges.push_back(edge);
        }
    }

    // Check if the must-include edges form a connected graph
    // Use Union-Find (Disjoint Set Union) to check connectivity
    vector<long long> parent(n);
    vector<long long> rank(n);

    auto find = [&](long long x) -> long long {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    };

    auto union_set = [&](long long x, long long y) -> bool {
        long long root_x = find(x);
        long long root_y = find(y);
        if (root_x == root_y) {
            return false;
        }
        if (rank[root_x] < rank[root_y]) {
            parent[root_x] = root_y;
        } else {
            parent[root_y] = root_x;
            if (rank[root_x] == rank[root_y]) {
                rank[root_x]++;
            }
        }
        return true;
    };

    for (auto& edge : must_edges) {
        union_set(edge[0], edge[1]);
    }

    // Check if all nodes are connected with must-include edges
    long long root = find(0);
    for (long long i = 1; i < n; ++i) {
        if (find(i) != root) {
            return -1;
        }
    }

    // If must-include edges already form a spanning tree, return the minimum strength
    if (must_edges.size() == n - 1) {
        long long min_strength = LLONG_MAX;
        for (auto& edge : must_edges) {
            min_strength = min(min_strength, edge[2]);
        }
        return min_strength;
    }

    // Sort optional edges by strength (we want to try to include the strongest ones first)
    sort(optional_edges.begin(), optional_edges.end(), [](const vector<long long>& a, const vector<long long>& b) {
        return a[2] > b[2];
    });

    // Use a priority queue to keep track of the edges with the lowest strength in the spanning tree
    priority_queue<pair<long long, long long>, vector<pair<long long, long long>>, greater<pair<long long, long long>>> pq;

    // Initialize the DSU with the must-include edges
    for (long long i = 0; i < n; ++i) {
        parent[i] = i;
        rank[i] = 0;
    }

    for (auto& edge : must_edges) {
        union_set(edge[0], edge[1]);
    }

    // Try to include optional edges to increase the minimum strength
    long long used_k = 0;
    for (auto& edge : optional_edges) {
        // If we can use k to upgrade this edge, do so
        if (used_k < k) {
            // Upgrade the edge's strength
            long long new_strength = edge[2] * 2;
            // Add this edge to the priority queue
            pq.push({new_strength, edge[0], edge[1]});
            used_k++;
        } else {
            // Add the original strength of the edge to the priority queue
            pq.push({edge[2], edge[0], edge[1]});
        }
    }

    // Now, try to build a spanning tree using the must-include edges and the optional edges
    // We will use a modified Krusky's algorithm to select edges that maximize the minimum strength
    long long result = 0;
    long long edges_used = 0;

    while (!pq.empty()) {
        auto [strength, u, v] = pq.top();
        pq.pop();

        long long root_u = find(u);
        long long root_v = find(v);

        if (root_u != root_v) {
            union_set(u, v);
            result = max(result, strength);
            edges_used++;
            if (edges_used == n - 1) {
                break;
            }
        }
    }

    if (edges_used == n - 1) {
        return result;
    } else {
        return -1;
    }
}

